from flask import Flask, request, jsonify, render_template_string
import hashlib
import secrets
import time
import smtplib
from email.mime.text import MIMEText
from email.mime.multipart import MIMEMultipart
from datetime import datetime, timedelta
import sqlite3

app = Flask(__name__)
app.secret_key = secrets.token_hex(16)

# Database setup
def init_db():
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute('''CREATE TABLE IF NOT EXISTS users
                 (id INTEGER PRIMARY KEY, email TEXT UNIQUE, password TEXT,
                  mfa_enabled BOOLEAN DEFAULT FALSE, mfa_secret TEXT,
                  reset_token TEXT, reset_token_expires TIMESTAMP)''')
    conn.commit()
    conn.close()

# Email configuration
EMAIL_CONFIG = {
    'smtp_server': 'smtp.gmail.com',
    'smtp_port': 587,
    'email': 'your_email@gmail.com',
    'password': 'your_password'
}

def send_reset_email(email, reset_link):
    try:
        msg = MIMEMultipart()
        msg['From'] = EMAIL_CONFIG['email']
        msg['To'] = email
        msg['Subject'] = "MFA Reset Request"
        
        body = f"""
        Hello,
        
        You have requested to reset your MFA settings. Click the link below to disable MFA and regain access:
        
        {reset_link}
        
        This link will expire in 1 hour.
        
        If you didn't request this, please ignore this email.
        
        Best regards,
        Your App Team
        """
        
        msg.attach(MIMEText(body, 'plain'))
        
        server = smtplib.SMTP(EMAIL_CONFIG['smtp_server'], EMAIL_CONFIG['smtp_port'])
        server.starttls()
        server.login(EMAIL_CONFIG['email'], EMAIL_CONFIG['password'])
        server.send_message(msg)
        server.quit()
        
        return True
    except Exception as e:
        print(f"Error sending email: {e}")
        return False

def generate_reset_token():
    return secrets.token_urlsafe(32)

def get_user_by_email(email):
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users WHERE email = ?", (email,))
    user = c.fetchone()
    conn.close()
    return user

def update_user_mfa_status(email, enabled, secret=None):
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    if enabled:
        c.execute("UPDATE users SET mfa_enabled = TRUE, mfa_secret = ? WHERE email = ?", 
                 (secret, email))
    else:
        c.execute("UPDATE users SET mfa_enabled = FALSE, mfa_secret = NULL WHERE email = ?", 
                 (email,))
    conn.commit()
    conn.close()

def create_reset_token(email):
    token = generate_reset_token()
    expires = datetime.now() + timedelta(hours=1)
    
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("UPDATE users SET reset_token = ?, reset_token_expires = ? WHERE email = ?", 
             (token, expires, email))
    conn.commit()
    conn.close()
    
    return token

def verify_reset_token(token):
    conn = sqlite3.connect('users.db')
    c = conn.cursor()
    c.execute("SELECT * FROM users WHERE reset_token = ? AND reset_token_expires > ?", 
             (token, datetime.now()))
    user = c.fetchone()
    conn.close()
    return user

@app.route('/enable-mfa', methods=['POST'])
def enable_mfa():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    
    # Verify credentials first
    user = get_user_by_email(email)
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    # In a real app, verify password here
    # For demo purposes, we'll assume it's valid
    
    # Generate MFA secret (in real app, use a proper MFA library)
    mfa_secret = secrets.token_urlsafe(32)
    
    update_user_mfa_status(email, True, mfa_secret)
    
    return jsonify({'message': 'MFA enabled successfully'})

@app.route('/disable-mfa', methods=['POST'])
def disable_mfa():
    data = request.get_json()
    email = data.get('email')
    password = data.get('password')
    
    # Verify credentials first
    user = get_user_by_email(email)
    if not user:
        return jsonify({'error': 'User not found'}), 404
    
    # In a real app, verify password here
